def detect_tool_loops(thread_id):
    runs = client.threads.list_runs(thread_id)
    tool_calls = []
    for run in runs:
        for step in run.steps:
            for tool_call in step.tool_calls or []:
                tool_calls.append({
                    'tool': tool_call.type,
                    'name': tool_call.function.name if tool_call.function else None,
                    'timestamp': step.created_at
                })

    # Detect loops: same tool >5 times in 10 minutes
    recent_calls = tool_calls[-20:]  # Last 20 calls
    from collections import Counter
    tool_freq = Counter([call['name'] or call['tool'] for call in recent_calls])

    loops = {tool: count for tool, count in tool_freq.items() if count >= 5}
    return len(loops) > 0, loops

