import { ProjectsClient } from '@azure/ai-projects';

const client = new ProjectsClient('https://your-project.api.azure.com', new DefaultAzureCredential());

interface ToolCall {
  tool: string;
  name?: string;
  timestamp: number;
}

const toolHistory: ToolCall[] = [];

const MAX_HISTORY = 50;
const LOOP_THRESHOLD = 5;

function detectLoopPattern(threadId: string): boolean {
  // Stream run events
  const stream = client.threads.streamRun(threadId);

  stream.on('step_delta', (step) => {
    if (step.tool_calls) {
      step.tool_calls.forEach((toolCall) => {
        toolHistory.push({
          tool: toolCall.type,
          name: toolCall.function?.name,
          timestamp: Date.now()
        });

        if (toolHistory.length > MAX_HISTORY) {
          toolHistory.shift();
        }
      });
    }
  });

  // Check for loops every 10 events
  setInterval(() => {
    const recent = toolHistory.slice(-20);
    const toolCounts = recent.reduce((acc, call) => {
      const key = call.name || call.tool;
      acc[key] = (acc[key] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    const hasLoop = Object.values(toolCounts).some(count => count >= LOOP_THRESHOLD);
    if (hasLoop) {
      console.log('🔄 Tool loop detected:', toolCounts);
      return true;
    }
  }, 10000);

  return false;
}

