from azure.ai.projects import ProjectsClient
import time
from typing import Dict, Set

class ToolLoopGuard:
    def __init__(self):
        self.tool_cache: Dict[str, Set[str]] = {}
        self.cache_ttl = 300  # 5 minutes

    def should_execute(self, thread_id: str, tool_name: str, tool_args: str) -> bool:
        cache_key = f'{thread_id}:{tool_name}'
        tool_signature = f'{tool_name}:{hash(str(tool_args))}'  

        now = time.time()
        if cache_key not in self.tool_cache:
            self.tool_cache[cache_key] = set()

        # Clean expired entries
        self.tool_cache[cache_key] = {
            sig for sig in self.tool_cache[cache_key] 
            if now - self.tool_cache[cache_key][sig] < self.cache_ttl
        }

        if tool_signature in self.tool_cache[cache_key]:
            print(f'⏭️ Skipping duplicate tool: {tool_name}')
            return False

        self.tool_cache[cache_key][tool_signature] = now
        return True

