from azure.ai.projects import ProjectsClient

class ToolLimitEnforcer:
    def __init__(self, max_tools_per_thread=20):
        self.max_tools = max_tools_per_thread
        self.thread_counters = {}

    def check_limit(self, thread_id: str) -> bool:
        if thread_id not in self.thread_counters:
            self.thread_counters[thread_id] = 0

        if self.thread_counters[thread_id] >= self.max_tools:
            return False

        self.thread_counters[thread_id] += 1
        return True

    def get_status(self, thread_id: str) -> dict:
        remaining = max(0, self.max_tools - self.thread_counters.get(thread_id, 0))
        return {'remaining_tools': remaining, 'limit': self.max_tools}

enforcer = ToolLimitEnforcer()

def before_tool_call(thread_id: str, tool_call):
    if not enforcer.check_limit(thread_id):
        return {
            'role': 'assistant',
            'content': f'Tool limit exceeded. Status: {enforcer.get_status(thread_id)}. Please rephrase your request.'
        }
    return None

class LoopRecoveryHandler {
  private toolCounts: Map<string, number> = new Map();
  private MAX_CALLS = 5;

  shouldRecover(threadId: string, toolName: string): string | null {
    const key = `${threadId}:${toolName}`;
    const count = (this.toolCounts.get(key) || 0) + 1;
    this.toolCounts.set(key, count);

    if (count >= this.MAX_CALLS) {
      return `🔄 Loop detected for tool '${toolName}'. Switching to summary mode:\n\nSummary of previous results:\n• Key findings from recent tool calls\n• No new information from repeated searches\n• Continuing with available data...`;
    }

    return null;
  }

  resetThread(threadId: string) {
    // Reset counters for new conversation turn
    Array.from(this.toolCounts.keys())
      .filter(key => key.startsWith(threadId))
      .forEach(key => this.toolCounts.delete(key));
  }
}

